`./stdin-event.ts`:
```ts
/// <reference lib="deno.unstable" />

import { delay } from "https://deno.land/std@0.144.0/async/delay.ts";

async function handleInput(
  callback: (chunk: Uint8Array) => void,
): Promise<void> {
  const isAtty = Deno.isatty(Deno.stdin.rid);
  if (isAtty) Deno.setRaw(Deno.stdin.rid, true, { cbreak: true });
  for await (const chunk of Deno.stdin.readable) callback(chunk);
  if (isAtty) Deno.setRaw(Deno.stdin.rid, false);
}

async function main() {
  console.log("🏁", "Start");

  handleInput((chunk) => console.log("⌨️", { chunk }))
    .catch((ex) => {
      if (ex instanceof Deno.errors.BadResource) {
        console.warn("stdin is closed");
      } else throw ex;
    });

  // wait 5s to simulate some other work
  for (let i = 5; i > 0; i -= 1) {
    console.log("⏱️", i);
    await delay(1e3);
  }

  console.log("🏁", "End");
  Deno.exit(0);
}

main();

```

