```
class ConfigManager {

...

	// File watcher for config files
	private configWatcher: Deno.FsWatcher | null = null;
	private watchedConfigPaths = new Set<string>();
	private watcherDebounceTimer: number | null = null;
	private isWatcherActive = false;

	/**
	 * Update watcher with new paths (restart with updated path list)
	 */
	private async updateConfigWatcher(): Promise<void> {
		if (this.isWatcherActive) {
			this.stopConfigWatcher();
		}
		await this.startConfigWatcher();
	}
	
	/**
	 * Start the file system watcher for config files
	 */
	private async startConfigWatcher(): Promise<void> {
		const paths = Array.from(this.watchedConfigPaths);
	
		if (paths.length === 0 || this.isWatcherActive) return;
	
		try {
			// Filter to only existing paths
			const existingPaths = [];
			for (const path of paths) {
				try {
					await Deno.stat(path);
					existingPaths.push(path);
				} catch {
					// Path doesn't exist yet
				}
			}
	
			if (existingPaths.length === 0) return;
	
			logger.info(`ConfigManager: Watching ${existingPaths.length} config files`);
			this.configWatcher = Deno.watchFs(existingPaths);
			this.isWatcherActive = true;
	
			// Process events in background
			(async () => {
				try {
					for await (const event of this.configWatcher!) {
						if (event.kind === 'modify' || event.kind === 'create') {
							logger.debug(`ConfigManager: Config change detected: ${event.paths.join(', ')}`);
	
							// Debounce
							if (this.watcherDebounceTimer !== null) {
								clearTimeout(this.watcherDebounceTimer);
							}
	
							this.watcherDebounceTimer = setTimeout(async () => {
								await this.handleConfigChange(event);
								this.watcherDebounceTimer = null;
							}, 500);
						}
					}
				} catch (error) {
					if (this.isWatcherActive) {
						logger.warn(`ConfigManager: Watcher error: ${(error as Error).message}`);
					}
				}
			})();
		} catch (error) {
			logger.error(`ConfigManager: Failed to start watcher: ${(error as Error).message}`);
		}
	}
	
	/**
	 * Stop the file system watcher
	 */
	private stopConfigWatcher(): void {
		if (this.watcherDebounceTimer !== null) {
			clearTimeout(this.watcherDebounceTimer);
			this.watcherDebounceTimer = null;
		}
	
		if (this.configWatcher) {
			try {
				this.configWatcher.close();
				logger.debug('ConfigManager: Watcher stopped');
			} catch (error) {
				logger.warn(`ConfigManager: Error stopping watcher: ${(error as Error).message}`);
			}
			this.configWatcher = null;
		}
	
		this.isWatcherActive = false;
	}

	// Convenience methods

	/**
	 * Start watching config files for changes
	 * Called during startup
	 */
	public async startWatching(): Promise<void> {
		const paths = [
			// global config
			join(await getConfigDir(), 'config.yaml'),
			// project configs
			...(await this.getAllProjectConfigPaths()),
		];

		paths.forEach((p) => this.watchedConfigPaths.add(p));
		await this.startConfigWatcher();
	}

	/**
	 * Stop watching config files
	 * Called during shutdown
	 */
	public stopWatching(): void {
		this.stopConfigWatcher();
	}

...

}
```

